// Build date range: now → +7 days
const now = new Date();
const end = new Date(now.getTime() + 7 * 24 * 60 * 60 * 1000);
return [{ json: { startTime: now.toISOString(), endTime: end.toISOString() } }];

const response = $input.first().json;
const slots = response?.data?.slots || {};

if (!slots || Object.keys(slots).length === 0) {
  return [{ json: {
    message: 'Prajwal has no available slots in the next 7 days. Please suggest the caller WhatsApp him directly at +977-9869375992 to arrange a time.'
  }}];
}

const lines = [];
for (const [date, times] of Object.entries(slots)) {
  if (!times || times.length === 0) continue;
  const dateObj = new Date(date + 'T00:00:00');
  const dayName = dateObj.toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' });
  const timeStrings = times.slice(0, 5).map(t => {
    const d = new Date(t.time);
    return d.toLocaleTimeString('en-US', { hour: '2-digit', minute: '2-digit', hour12: true, timeZone: 'Asia/Katmandu' });
  });
  lines.push(`${dayName}: ${timeStrings.join(', ')}`);
}

if (lines.length === 0) {
  return [{ json: { message: 'No available slots found in the next 7 days. Ask the caller to WhatsApp Prajwal at +977-9869375992.' }}];
}

const message = 'Here are Prajwal\'s available slots over the next 7 days. ' + lines.join('. ') + '. Which time works best for you?';

return [{ json: { message, slots: lines } }];
